algorithm:
Iteratively attempt to insert each ship into existing non-empty routes using cheapest-cost-first search with full rollback; if no feasible insertion found in existing routes, create a new empty assign for fallback insertion.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		assignIdx int
		costDelta float64
	}
	for shipID := 0; shipID < len(oris); shipID++ {
		id := total_ship + shipID
		ori, des := oris[shipID], dess[shipID]
		bestCand := cand{-1, 0.0}
		savedStates := make([]float64, dispatch.AssignsLen)
		savedCosts := make([]bool, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedStates[i] = dispatch.Assigns[i].Cost
			savedCosts[i] = false
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			addOK := dispatch.Assigns[i].AddShip(id, ori, des)
			if !addOK {
				continue
			}
			dispatch.Assigns[i].GenRoute()
			if dispatch.Assigns[i].Cost >= 0 {
				newCost := dispatch.Assigns[i].Cost
				oldCost := savedStates[i]
				delta := newCost - oldCost
				if bestCand.assignIdx == -1 || delta < bestCand.costDelta {
					bestCand.assignIdx = i
					bestCand.costDelta = delta
				}
				savedCosts[i] = true
			}
			dispatch.Assigns[i].RemoveShip(id)
			dispatch.Assigns[i].GenRoute()
		}
		if bestCand.assignIdx != -1 {
			idx := bestCand.assignIdx
			dispatch.Assigns[idx].AddShip(id, ori, des)
			dispatch.Assigns[idx].GenRoute()
			continue
		}
		fallbackMade := false
		if dispatch.AssignsLen < MAXASSIGNS {
			idx := dispatch.AssignsLen
			ok := dispatch.Assigns[idx].AddShip(id, ori, des)
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					dispatch.AssignsLen++
					fallbackMade = true
				} else {
					dispatch.Assigns[idx].RemoveShip(id)
					dispatch.Assigns[idx].GenRoute()
				}
			}
		}
		if !fallbackMade && dispatch.AssignsLen < MAXASSIGNS {
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					ok := dispatch.Assigns[i].AddShip(id, ori, des)
					if ok {
						dispatch.Assigns[i].GenRoute()
						if dispatch.Assigns[i].Cost >= 0 {
							dispatch.AssignsLen = i + 1
							fallbackMade = true
							break
						} else {
							dispatch.Assigns[i].RemoveShip(id)
							dispatch.Assigns[i].GenRoute()
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

